const container=document.getElementById("carousel"),cards=document.querySelectorAll(".polaroid");let currentIndex=0,autoplayTimer=null;const randomRange=(t,n)=>Math.random()*(n-t)+t;function updateCarouselState(){cards.forEach((t,n)=>{if(n===currentIndex)t.classList.add("active"),t.style.transform="translate3d(0, 0, 0) rotate(0deg)",t.style.opacity="1",t.style.zIndex="10";else{t.classList.remove("active");let e=n-currentIndex;e<0&&(e+=cards.length);const o=randomRange(-12,12),s=randomRange(-8,12),a=randomRange(-6,6);t.style.transform=`translate3d(${o}px, ${s}px, -${e*10}px) rotate(${a}deg)`,t.style.opacity=e===cards.length-1?"0":"0.85",t.style.zIndex=10-e}})}function rotateCards(){const t=cards[currentIndex],n=randomRange(0,2*Math.PI),e=400,o=Math.cos(n)*e,s=Math.sin(n)*e,a=randomRange(-35,35);t.style.opacity="0",t.style.transform=`translate3d(${o}px, ${s}px, 50px) rotate(${a}deg)`,setTimeout(()=>{currentIndex=(currentIndex+1)%cards.length,updateCarouselState()},350)}function startAutoplay(){autoplayTimer||(autoplayTimer=setInterval(rotateCards,6e3))}updateCarouselState(),startAutoplay();
